[package]
name = "ritual-block-verification"
version = "0.1.0"
edition = "2021"

[dependencies]
reth-primitives = { workspace = true }
reth-primitives-traits = { workspace = true }
reth-transaction-pool = { workspace = true }
reth-storage-api = { workspace = true }
reth-revm = { workspace = true }
revm = { workspace = true }
alloy-primitives = { workspace = true }
alloy-sol-types = { workspace = true }
alloy-evm = { workspace = true }
alloy-consensus = { workspace = true }
alloy-rlp = { workspace = true }
reth-ethereum-primitives = { workspace = true }
ritual-metrics = { path = "../ritual-metrics" }
ritual-async-commitment-validator = { workspace = true }
ritual-async-fees = { workspace = true }
ritual-precompile-addresses = { workspace = true }
ritual-async-registry = { workspace = true }
ritual-scheduled-verification = { workspace = true }
ritual-heartbeat-tracker = { workspace = true }
ritual-tee-registry-reader = { workspace = true }
ritual-spc-signature = { path = "../ritual-spc-signature" }
ritual-sequencing-rights = { path = "../ritual-sequencing-rights" }
ritual-precompile-codecs = { workspace = true }
reth-evm = { workspace = true, features = ["std"] }
reth-evm-ethereum = { workspace = true }
rayon = { workspace = true }
ritual-async-inspector = { workspace = true }
thiserror = { workspace = true }
tracing = { workspace = true }

[dev-dependencies]
proptest = "1.4"

[features]
default = []
async-context = ["reth-evm/async-context", "alloy-evm/async-context"]

# root Cargo.toml wiring:
"crates/ritual-block-verification/"
ritual-block-verification = { path = "./crates/ritual-block-verification" }
